Implementation file: src/game-of-life.ts
Passing tests: 7
Recent changes: Added reproduction logic — finds dead cells adjacent to living cells, checks if they have exactly 3 living neighbors, and adds them to the output along with survivors.

Current implementation:
```typescript
export type Cell = [number, number];

const isNeighbor = (cell: Cell, other: Cell): boolean =>
  !(other[0] === cell[0] && other[1] === cell[1]) &&
  Math.abs(other[0] - cell[0]) <= 1 &&
  Math.abs(other[1] - cell[1]) <= 1;

const countNeighbors = (cell: Cell, livingCells: Cell[]): number =>
  livingCells.filter((other) => isNeighbor(cell, other)).length;

export function nextGeneration(livingCells: Cell[]): Cell[] {
  const survivors = livingCells.filter(
    (cell) => {
      const neighbors = countNeighbors(cell, livingCells);
      return neighbors === 2 || neighbors === 3;
    }
  );

  const deadNeighbors = new Map<string, Cell>();
  for (const cell of livingCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const candidate: Cell = [cell[0] + dx, cell[1] + dy];
        const key = `${candidate[0]},${candidate[1]}`;
        if (!livingCells.some((c) => c[0] === candidate[0] && c[1] === candidate[1])) {
          deadNeighbors.set(key, candidate);
        }
      }
    }
  }

  const born = [...deadNeighbors.values()].filter(
    (cell) => countNeighbors(cell, livingCells) === 3
  );

  return [...survivors, ...born];
}
```

Consider extracting the dead neighbor candidate finding into a helper function for readability, and consider using a Set-based lookup for living cells instead of .some() for consistency.

